const r = $json;
const existing = ["How to Protest a Data Center's Groundwater Permit in Texas","The Rule of Capture, Explained","The Trinity Aquifer Under Threat: data center boom","When the Ground Sinks: data center pumping and subsidence","Is Your Well Water Safe? Contamination Testing","Projecting Data Center Water Usage and Cooling Demands for 2026","Texas Moves to Rein In the Data Center Boom","Data Center Air Pollution in Texas: A Landowner's Guide","Diesel Generators and Neighborhood Air: The Midlothian Question","Crypto Mine vs. Data Center in Texas","Data Center Noise and Texas Nuisance Law","Proving a Data Center Lowered Your Property Value","Is There a Texas Data Center Lawsuit","What to Do If Your Well Runs Dry","Abilene Data Center Water Use","Corsicana Data Center Property Value","Granbury Data Center Noise","Granbury Data Center Water","Midlothian Data Center Water Use","Red Oak Data Center Property Value","Trinity Aquifer water loss in Ellis County"];
const sys = 'You are a staff writer for BigDataDamage.com, a Texas public-interest watchdog that helps rural landowners hold data centers accountable. CORE STANCE, frame every article through this: we are NOT anti-AI, anti-technology, or anti-progress. The problem is that data centers built for AI too often FAIL TO COMPENSATE people when they take land, drain or contaminate water, or destroy the quiet enjoyment of a home. Every article should move from the specific HARM, to the landowner RIGHTS at stake, to concrete steps to document the harm and seek compensation or recourse. Keep it about accountability and just compensation; never doom, fear-mongering, or opposition to technology itself. Audience: worried, non-expert Texas landowners. Voice: calm, plain, authoritative, specific; never hypey, salesy, or alarmist. OUTPUT: a single Markdown document with YAML frontmatter and NOTHING else (no code fences, no preamble). Frontmatter keys in order: title, excerpt, date, author (Big Data Damage), harm, location (omit if none), imageQuery, seoTitle, seoDescription. imageQuery is a 3 to 6 word LITERAL stock-photo search phrase for a concrete, realistic photo that matches the article (good examples: data center construction site; dry cracked riverbed; house foundation crack; texas ranch windmill; factory smokestack emissions). Use concrete physical subjects only; never abstract ideas, wildlife, flowers, butterflies, or generic nature scenery. RULES: Markdown only; GFM tables allowed; NO raw HTML, NO style or iframe tags, NO inline CSS. To embed a video put a bare YouTube link on its own line. Cite real sources inline as Markdown links, prefer grounded results, use ranges not false precision, never invent statistics, case names, statutes, or quotes. Structure: 2-3 short intro paragraphs, then 3-5 H2 sections, then an H2 Frequently Asked Questions with 4-6 H3 Q&As, then a short closing H2 that points the reader toward documenting harm and knowing their rights. About 900-1300 words. Add the internal links from the brief using root-relative paths like /damage/water. No tool-attribution footer. This is a YMYL legal-adjacent topic: be accurate and measured; make clear this is general information, not legal advice about a specific property.';
const brief = 'Write a complete article for this brief.
Title: ' + r.title + '
Target keyword: ' + r.keyword + '
Harm: ' + r.harm + '
Location: ' + (r.location || 'none') + '
Internal links to include: ' + (r.internal_links || 'none') + '
Angle/notes: ' + (r.notes || 'none') + '

Do NOT duplicate the angle or core stats of these existing articles: ' + existing.join('; ');
const body = { systemInstruction: { parts: [{ text: sys }] }, contents: [{ role: 'user', parts: [{ text: brief }] }], tools: [{ googleSearch: {} }] };
return [{ json: { body: body, row_number: r.row_number, title: r.title } }];

// Code node "Parse & validate" — extracts frontmatter + body from Gemini's
// output (handles ```yaml fences, --- delimiters, or whole-doc-wrapped output),
// normalizes to quoted --- YAML, validates, and base64-encodes the final .md.
const TB = String.fromCharCode(96, 96, 96);
const parts = $json.candidates?.[0]?.content?.parts || [];
let text = parts.map(p => p.text || '').join('');
text = text.replace(/\r\n/g, '\n').trim();
text = text.replace(new RegExp('^' + TB + '[a-zA-Z]*[ \\t]*\\n'), '');
text = text.replace(new RegExp('\\n?' + TB + '[ \\t]*$'), '');
text = text.trim();

const keys = ['title','excerpt','date','author','harm','location','seoTitle','seoDescription'];
const lines = text.split('\n');
const data = {};
let i = 0;
if (lines[0] && lines[0].trim() === '---') i = 1;
for (; i < lines.length; i++) {
  const t = lines[i].trim();
  if (t === '---') { i++; break; }
  if (t.startsWith(TB)) { if (Object.keys(data).length) { i++; break; } else { continue; } }
  const mm = lines[i].match(/^([A-Za-z]+):\s*(.*)$/);
  if (mm && keys.includes(mm[1])) { data[mm[1]] = mm[2].trim().replace(/^["']|["']$/g, ''); }
  else if (t === '') { if (Object.keys(data).length) { i++; break; } }
  else { break; }
}
let body = lines.slice(i).join('\n').trim();

if (!data.title) { throw new Error('No title. First 200: ' + text.slice(0, 200)); }
const fm = keys.filter(k => data[k]).map(k => k + ': "' + data[k].replace(/"/g, '\\"') + '"').join('\n');
const title = data.title;
const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 80);

const stripped = body.replace(/^\s*https?:\/\/\S+\s*$/gim, '');
if (/<\/?[a-z][\s\S]*?>/i.test(stripped)) { throw new Error('Raw HTML detected in body'); }
const wc = body.split(/\s+/).filter(Boolean).length;
if (wc < 250) { throw new Error('Draft too short: ' + wc + ' words'); }

const finalMd = '---\n' + fm + '\n---\n\n' + body + '\n';
const contentB64 = Buffer.from(finalMd, 'utf8').toString('base64');
return [{ json: { slug: slug, path: 'src/content/articles/' + slug + '.md', title: title, contentB64: contentB64, row_number: $('Build Gemini request').item.json.row_number } }];
